class Item {
    private Long id;
    private String name;
    private String description;
    private double price;

    public Item() {}

    public Item(Long id, String name, String description, double price) {
        this.id = id;
        this.name = name;
        this.description = description;
        this.price = price;
    }

    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }
    public double getPrice() { return price; }
    public void setPrice(double price) { this.price = price; }

    @Override
    public String toString() {
        return "Item{id=" + id + ", name='" + name + "'}";
    }
}

class ApiResponse<T> {
    private String status;
    private String message;
    private T data;

    public ApiResponse(String status, String message, T data) {
        this.status = status;
        this.message = message;
        this.data = data;
    }

    public String getStatus() { return status; }
    public void setStatus(String status) { this.status = status; }
    public String getMessage() { return message; }
    public void setMessage(String message) { this.message = message; }
    public T getData() { return data; }
    public void setData(T data) { this.data = data; }
}

@RestController
@RequestMapping("/api/items")
class ItemController {

    private static final Logger logger = LoggerFactory.getLogger(ItemController.class);

    private final Map<Long, Item> itemStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    @GetMapping
    public ResponseEntity<ApiResponse<List<Item>>> getAllItems() {
        logger.info("Received request to fetch all items");
        List<Item> items = new ArrayList<>(itemStore.values());
        logger.info("Returning {} items", items.size());
        return ResponseEntity.ok(new ApiResponse<>("success", "Items retrieved successfully", items));
    }

    @GetMapping("/{id}")
    public ResponseEntity<ApiResponse<Item>> getItemById(@PathVariable Long id) {
        logger.info("Received request to fetch item with id={}", id);
        Item item = itemStore.get(id);
        if (item == null) {
            logger.warn("Item with id={} not found", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>("error", "Item not found with id: " + id, null));
        }
        logger.info("Successfully retrieved item: {}", item);
        return ResponseEntity.ok(new ApiResponse<>("success", "Item retrieved successfully", item));
    }

    @PostMapping
    public ResponseEntity<ApiResponse<Item>> createItem(@RequestBody Item item) {
        logger.info("Received request to create item with name='{}'", item.getName());

        if (item.getName() == null || item.getName().trim().isEmpty()) {
            logger.warn("Item creation failed: name is required");
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(new ApiResponse<>("error", "Item name is required", null));
        }

        if (item.getPrice() < 0) {
            logger.warn("Item creation failed: price cannot be negative, received price={}", item.getPrice());
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(new ApiResponse<>("error", "Price cannot be negative", null));
        }

        Long id = idGenerator.getAndIncrement();
        item.setId(id);
        itemStore.put(id, item);
        logger.info("Successfully created item: {}", item);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(new ApiResponse<>("success", "Item created successfully", item));
    }

    @PutMapping("/{id}")
    public ResponseEntity<ApiResponse<Item>> updateItem(@PathVariable Long id, @RequestBody Item item) {
        logger.info("Received request to update item with id={}", id);

        Item existingItem = itemStore.get(id);
        if (existingItem == null) {
            logger.warn("Update failed: item with id={} not found", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>("error", "Item not found with id: " + id, null));
        }

        if (item.getName() == null || item.getName().trim().isEmpty()) {
            logger.warn("Update failed for item id={}: name is required", id);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(new ApiResponse<>("error", "Item name is required", null));
        }

        if (item.getPrice() < 0) {
            logger.warn("Update failed for item id={}: price cannot be negative, received price={}", id, item.getPrice());
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(new ApiResponse<>("error", "Price cannot be negative", null));
        }

        existingItem.setName(item.getName());
        existingItem.setDescription(item.getDescription());
        existingItem.setPrice(item.getPrice());
        itemStore.put(id, existingItem);
        logger.info("Successfully updated item: {}", existingItem);
        return ResponseEntity.ok(new ApiResponse<>("success", "Item updated successfully", existingItem));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<ApiResponse<Void>> deleteItem(@PathVariable Long id) {
        logger.info("Received request to delete item with id={}", id);

        Item removedItem = itemStore.remove(id);
        if (removedItem == null) {
            logger.warn("Delete failed: item with id={} not found", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>("error", "Item not found with id: " + id, null));
        }

        logger.info("Successfully deleted item: {}", removedItem);
        return ResponseEntity.ok(new ApiResponse<>("success", "Item deleted successfully", null));
    }

    @GetMapping("/search")
    public ResponseEntity<ApiResponse<List<Item>>> searchItems(@RequestParam String name) {
        logger.info("Received search request with name='{}'", name);

        if (name == null || name.trim().isEmpty()) {
            logger.warn("Search failed: search term is empty");
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(new ApiResponse<>("error", "Search term cannot be empty", null));
        }

        List<Item> results = new ArrayList<>();
        for (Item item : itemStore.values()) {
            if (item.getName().toLowerCase().contains(name.toLowerCase())) {
                results.add(item);
            }
        }
        logger.info("Search for '{}' returned {} results", name, results.size());
        return ResponseEntity.ok(new ApiResponse<>("success", "Search completed successfully", results));
    }
}

@RestController
@RequestMapping("/api/health")
class HealthController {

    private static final Logger logger = LoggerFactory.getLogger(HealthController.class);

    @GetMapping
    public ResponseEntity<ApiResponse<Map<String, String>>> healthCheck() {
        logger.info("Health check requested");
        Map<String, String> healthInfo = new HashMap<>();
        healthInfo.put("status", "UP");
        healthInfo.put("timestamp", new Date().toString());
        healthInfo.put("service", "item-api");
        logger.info("Health check passed: service is UP");
        return ResponseEntity.ok(new ApiResponse<>("success", "Service is healthy", healthInfo));
    }
}

@ControllerAdvice
class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<Void>> handleGenericException(Exception ex) {
        logger.error("Unhandled exception occurred: {}", ex.getMessage(), ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(new ApiResponse<>("error", "An unexpected error occurred", null));
    }

    @ExceptionHandler(org.springframework.web.bind.MissingServletRequestParameterException.class)
    public ResponseEntity<ApiResponse<Void>> handleMissingParams(
            org.springframework.web.bind.MissingServletRequestParameterException ex) {
        logger.warn("Missing required request parameter: {}", ex.getParameterName());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ApiResponse<>("error", "Missing required parameter: " + ex.getParameterName(), null));
    }

    @ExceptionHandler(org.springframework.web.method.annotation.MethodArgumentTypeMismatchException.class)
    public ResponseEntity<ApiResponse<Void>> handleTypeMismatch(
            org.springframework.web.method.annotation.MethodArgumentTypeMismatchException ex) {
        logger.warn("Type mismatch for parameter '{}': value '{}' is not valid", ex.getName(), ex.getValue());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ApiResponse<>("error", "Invalid parameter type for: " + ex.getName(), null));
    }

    @ExceptionHandler(org.springframework.http.converter.HttpMessageNotReadableException.class)
    public ResponseEntity<ApiResponse<Void>> handleMessageNotReadable(
            org.springframework.http.converter.HttpMessageNotReadableException ex) {
        logger.warn("Malformed request body: {}", ex.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ApiResponse<>("error", "Malformed request body", null));
    }
}